class ASTNode:
    def __init__(self, type, value=None, op=None, left=None, right=None, operand=None):
        self.type = type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    # Tokenizer
    def tokenize(s):
        tokens = []
        i = 0
        while i < len(s):
            if s[i].isdigit() or s[i] == ".":
                # Parse number
                start = i
                while i < len(s) and (s[i].isdigit() or s[i] == "."):
                    i += 1
                tokens.append(("NUMBER", s[start:i]))
            elif s[i] == "+" or s[i] == "-" or s[i] == "*" or s[i] == "/":
                # Parse operator
                tokens.append(("OPERATOR", s[i]))
                i += 1
            elif s[i] == "(" or s[i] == ")":
                # Parse parenthesis
                tokens.append(("PAREN", s[i]))
                i += 1
            else:
                raise ValueError(f"Invalid character: {s[i]}")
        return tokens

    tokens = tokenize(expression)

    # Parser with precedence
    def parse_expression(tokens, precedence=0):
        if not tokens:
            raise ValueError("Unexpected end of expression")

        # Handle unary minus
        if tokens[0][0] == "OPERATOR" and tokens[0][1] == "-":
            # Check if this is unary minus (preceded by operator or start of expression)
            if len(tokens) > 1 and (
                tokens[0][0] == "OPERATOR"
                or tokens[0][0] == "PAREN"
                or tokens[0][1] == "("
            ):
                # Unary minus
                tokens.pop(0)  # Remove the minus
                operand = parse_expression(tokens, 11)  # Higher precedence for unary
                return ASTNode("unary", op="-", operand=operand)

        # Parse leftmost operand
        if tokens[0][0] == "NUMBER":
            value = float(tokens.pop(0)[1])
            node = ASTNode("number", value=value)
        elif tokens[0][0] == "PAREN" and tokens[0][1] == "(":
            tokens.pop(0)  # Remove '('
            node = parse_expression(tokens, 0)
            if not tokens or tokens[0][0] != "PAREN" or tokens[0][1] != ")":
                raise ValueError("Unmatched parenthesis")
            tokens.pop(0)  # Remove ')'
        else:
            raise ValueError("Invalid expression")

        # Handle binary operators
        while tokens and tokens[0][0] == "OPERATOR":
            op = tokens[0][1]
            op_precedence = (
                10 if op in ["+", "-"] else 20
            )  # Lower precedence for +, -; higher for *, /

            if op_precedence < precedence:
                break

            tokens.pop(0)  # Remove operator
            right = parse_expression(tokens, op_precedence)
            node = ASTNode("binop", op=op, left=node, right=right)

        return node

    # Parse the expression
    try:
        result = parse_expression(tokens)
        if tokens:  # There are still tokens left
            raise ValueError("Invalid expression")
        return result
    except IndexError:
        raise ValueError("Invalid expression")


def evaluate(node):
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
    else:
        raise ValueError("Invalid AST node type")
